const sales = [12000, 8500, 21000, 4500, 17000, 9000, 25000];

const total    = sales.reduce((sum, s) => sum + s, 0);
const average  = total / sales.length;
const highest  = Math.max(...sales);
const above10k = sales.filter(s => s > 10000).length;

console.log("Total:",    total);
console.log("Average:",  average);
console.log("Highest:",  highest);
console.log("Above 10k:", above10k);
